INSERT INTO public.products (sku, model, series, name, description, category, unit_price, stock_status, slug, image_url, gallery_urls, tags, is_featured, is_active, warranty_months, warranty_type) VALUES
('JTSN-JETSON-ORIN-NANO-MODULE', '900-13767-0030-000', 'Jetson Series', 'Jetson Orin Nano โมดูล', E'ประสิทธิภาพ AI สูงสุด 67 TOPS ในขนาด 69.6x45mm GPU 1024-core Ampere, CPU 6-core\n\nUp to 67 TOPS in 69.6x45mm. 1024-core Ampere GPU, 6-core Arm Cortex-A78AE.\n\nSpecs: ประสิทธิภาพ AI: 34/67 TOPS | GPU: 512/1024-core Ampere | Memory: 4/8GB LPDDR5 | Power: 5-15W', 'โมดูล Jetson', 22900, 'available', 'jetson-orin-nano-module', '/jetson-images/modules/orin-nano-module-1.png', ARRAY['/jetson-images/modules/orin-nano-module-1.png','/jetson-images/modules/orin-nano-module-2.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules','popular']::text[], true, true, 12, 'carry_in'),
('JTSN-JETSON-ORIN-NX-MODULE', 'JETSON-ORIN-NX-MODULE', 'Jetson Series', 'Jetson Orin NX โมดูล', E'สูงสุด 157 TOPS, GPU 1024-core Ampere, RAM 8/16GB, PCIe Gen4, แสดงผล 8K30\n\nUp to 157 TOPS, 1024-core Ampere, 8/16GB LPDDR5, PCIe Gen4, 8K30 display, pin-compatible with Orin Nano.\n\nSpecs: ประสิทธิภาพ AI: 117/157 TOPS | Memory: 8/16GB LPDDR5 | Power: 10-25W', 'โมดูล Jetson', 0, 'rfq', 'jetson-orin-nx-module', '/jetson-images/modules/orin-nx-module-1.png', ARRAY['/jetson-images/modules/orin-nx-module-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-AGX-ORIN-MODULE', 'JETSON-AGX-ORIN-MODULE', 'Jetson Series', 'Jetson AGX Orin โมดูล', E'โมดูล Jetson ทรงพลังที่สุด 275 TOPS, GPU 2048-core, RAM สูงสุด 64GB\n\nMost powerful Jetson — 275 TOPS, 2048-core Ampere GPU, 12-core CPU, up to 64GB LPDDR5.\n\nSpecs: ประสิทธิภาพ AI: Up to 275 TOPS | Memory: 32/64GB LPDDR5 | Power: 15-60W', 'โมดูล Jetson', 0, 'rfq', 'jetson-agx-orin-module', '/jetson-images/modules/agx-orin-module-1.png', ARRAY['/jetson-images/modules/agx-orin-module-1.png','/jetson-images/modules/agx-orin-module-2.png','/jetson-images/modules/agx-orin-module-3.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-THOR-MODULE', 'JETSON-THOR-MODULE', 'Jetson Series', 'Jetson Thor T5000 โมดูล', E'สถาปัตยกรรม Blackwell สำหรับหุ่นยนต์ฮิวแมนนอยด์และยานยนต์อัตโนมัติ\n\nNVIDIA Blackwell architecture for humanoid robots and autonomous vehicles.\n\nSpecs: ประสิทธิภาพ AI: 2070 TFLOPS | Architecture: NVIDIA Blackwell', 'โมดูล Jetson', 0, 'rfq', 'jetson-thor-module', '/jetson-images/modules/jetson-thor-t5000.png', ARRAY['/jetson-images/modules/jetson-thor-t5000.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules','new']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-THOR-T4000', 'JETSON-THOR-T4000', 'Jetson Series', 'Jetson Thor T4000 โมดูล', E'1200 TFLOPS, GPU 1536-core, CPU 12-core, RAM 64GB LPDDR5X, PCIe Gen5\n\n1200 TFLOPS, 1536-core Blackwell, 12-core Neoverse V3AE, 64GB LPDDR5X (273 GB/s), PCIe Gen5.\n\nSpecs: AI: 1200 TFLOPS FP4 | Memory: 64GB LPDDR5X | Power: 40-70W', 'โมดูล Jetson', 0, 'rfq', 'jetson-thor-t4000', '/jetson-images/modules/jetson-thor-t5000.png', ARRAY['/jetson-images/modules/jetson-thor-t5000.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules','new']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-AGX-XAVIER-MODULE', 'JETSON-AGX-XAVIER-MODULE', 'Jetson Series', 'Jetson AGX Xavier โมดูล', E'32 TOPS, GPU 512-core Volta, CPU 8-core, 32GB LPDDR4x, 2x NVDLA\n\n32 TOPS, 512-core Volta GPU, 8-core ARM v8.2, 32GB LPDDR4x, 2x NVDLA engines.\n\nSpecs: AI: 32 TOPS | Memory: 32GB LPDDR4x', 'โมดูล Jetson', 0, 'rfq', 'jetson-agx-xavier-module', '/jetson-images/modules/agx-xavier-module-1.png', ARRAY['/jetson-images/modules/agx-xavier-module-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-XAVIER-NX-MODULE', 'JETSON-XAVIER-NX-MODULE', 'Jetson Series', 'Jetson Xavier NX โมดูล', E'21 TOPS ในขนาด Nano, 384 CUDA + 48 Tensor Cores, 8GB LPDDR4x\n\n21 TOPS in Nano form factor (69.6x45mm). 384 CUDA + 48 Tensor Cores, 8GB LPDDR4x.\n\nSpecs: AI: 21 TOPS | Memory: 8GB LPDDR4x', 'โมดูล Jetson', 0, 'rfq', 'jetson-xavier-nx-module', '/jetson-images/modules/xavier-nx-module-1.png', ARRAY['/jetson-images/modules/xavier-nx-module-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-TX2-MODULE', 'JETSON-TX2-MODULE', 'Jetson Series', 'Jetson TX2 โมดูล', E'256 CUDA cores Pascal, CPU Denver 2 + ARM A57, 8GB LPDDR4, 32GB eMMC\n\n256 CUDA cores Pascal, dual Denver 2 + quad ARM A57, 8GB LPDDR4, 32GB eMMC.\n\nSpecs: GPU: 256 CUDA Pascal | Memory: 8GB LPDDR4', 'โมดูล Jetson', 0, 'rfq', 'jetson-tx2-module', '/jetson-images/modules/tx2-module-1.png', ARRAY['/jetson-images/modules/tx2-module-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-TX2-NX-MODULE', 'JETSON-TX2-NX-MODULE', 'Jetson Series', 'Jetson TX2 NX โมดูล', E'พลัง TX2 ในขนาดเท่า Nano (69.6x45mm)\n\nTX2 performance in Nano/Xavier NX form factor (69.6x45mm).\n\nSpecs: GPU: 256 CUDA Pascal | Memory: 4GB LPDDR4', 'โมดูล Jetson', 0, 'rfq', 'jetson-tx2-nx-module', '/jetson-images/modules/tx2-nx-module-1.png', ARRAY['/jetson-images/modules/tx2-nx-module-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-TX2I-MODULE', 'JETSON-TX2I-MODULE', 'Jetson Series', 'Jetson TX2i โมดูล (อุตสาหกรรม)', E'ระดับอุตสาหกรรม ทนอุณหภูมิสุดขั้ว มี ECC memory\n\nIndustrial-grade -40°C to +85°C, ECC memory, longer lifecycle.\n\nSpecs: อุณหภูมิ: -40°C to +85°C | Memory: 8GB LPDDR4 ECC', 'โมดูล Jetson', 0, 'rfq', 'jetson-tx2i-module', '/jetson-images/modules/tx2i-module-1.png', ARRAY['/jetson-images/modules/tx2i-module-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-NANO-MODULE', '900-13448-0020-000', 'Jetson Series', 'Jetson Nano โมดูล', E'Edge AI ระดับเริ่มต้น 128 CUDA Cores, CPU 4-core, 4GB LPDDR4, 16GB eMMC\n\nEntry-level edge AI. 128 CUDA cores Maxwell, quad ARM A57, 4GB LPDDR4, 16GB eMMC.\n\nSpecs: GPU: 128 CUDA Maxwell | Memory: 4GB LPDDR4', 'โมดูล Jetson', 12900, 'available', 'jetson-nano-module', '/jetson-images/modules/nano-module-1.png', ARRAY['/jetson-images/modules/nano-module-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','modules']::text[], true, true, 12, 'carry_in'),
('JTSN-ORIN-NANO-SUPER-DEVKIT', 'ORIN-NANO-SUPER-DEVKIT', 'Jetson Series', 'Jetson Orin Nano Super ชุดพัฒนา', E'ชุดพัฒนา Orin Nano Super อย่างเป็นทางการ 67 TOPS พร้อม Carrier Board + Power Supply\n\nOfficial NVIDIA Orin Nano Super Dev Kit. 67 TOPS. Carrier board + power supply included.\n\nSpecs: Module: Orin Nano 8GB (67 TOPS)', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'orin-nano-super-devkit', '/jetson-images/devkits/orin-nano-super-devkit-1.jpg', ARRAY['/jetson-images/devkits/orin-nano-super-devkit-1.jpg','/jetson-images/devkits/orin-nano-super-devkit-2.jpg','/jetson-images/devkits/orin-nano-super-devkit-3.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','devkits','best-seller']::text[], false, true, 12, 'carry_in'),
('JTSN-AGX-ORIN-DEVKIT', 'AGX-ORIN-DEVKIT', 'Jetson Series', 'Jetson AGX Orin ชุดพัฒนา', E'ชุดพัฒนาทรงพลังที่สุด 275 TOPS สำหรับเครื่องจักรอัตโนมัติและการแพทย์\n\nMost powerful dev kit. 275 TOPS for autonomous machines, robots, medical imaging.\n\nSpecs: AI: 275 TOPS | Memory: 32/64GB LPDDR5', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'agx-orin-devkit', '/jetson-images/devkits/agx-orin-devkit-1.jpg', ARRAY['/jetson-images/devkits/agx-orin-devkit-1.jpg','/jetson-images/devkits/agx-orin-devkit-2.jpg','/jetson-images/devkits/agx-orin-devkit-3.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','devkits']::text[], false, true, 12, 'carry_in'),
('JTSN-DGX-SPARK', 'DGX-SPARK', 'Jetson Series', 'NVIDIA DGX Spark', E'ซูเปอร์คอมพิวเตอร์ AI ตั้งโต๊ะ Blackwell สำหรับนักวิจัยและ Data Scientist\n\nDesktop AI supercomputer with NVIDIA Blackwell. For researchers and data scientists.\n\nSpecs: Architecture: NVIDIA Blackwell', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'dgx-spark', '/jetson-images/devkits/dgx-spark.png', ARRAY['/jetson-images/devkits/dgx-spark.png']::text[], ARRAY['nvidia','jetson','edge-ai','devkits','new']::text[], false, true, 12, 'carry_in'),
('JTSN-JETSON-THOR-DEVKIT', 'JETSON-THOR-DEVKIT', 'Jetson Series', 'Jetson Thor ชุดพัฒนา', E'ชุดพัฒนารุ่นใหม่ Jetson Thor 2070 TFLOPS Blackwell\n\nNext-gen dev kit with Jetson Thor. 2070 TFLOPS. Blackwell architecture.\n\nSpecs: AI: 2070 TFLOPS', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'jetson-thor-devkit', '/jetson-images/devkits/jetson-thor-devkit.png', ARRAY['/jetson-images/devkits/jetson-thor-devkit.png']::text[], ARRAY['nvidia','jetson','edge-ai','devkits','pre-order']::text[], false, true, 12, 'carry_in'),
('JTSN-IGX-ORIN-DEVKIT', 'IGX-ORIN-DEVKIT', 'Jetson Series', 'NVIDIA IGX Orin ชุดพัฒนา', E'ชุดพัฒนา IGX Orin สำหรับ AI อุตสาหกรรมและการแพทย์ Functional Safety\n\nIGX Orin Dev Kit for industrial and medical AI. Functional Safety + Enterprise Security.\n\nSpecs: Module: IGX Orin', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'igx-orin-devkit', '/jetson-images/devkits/igx-orin-devkit.png', ARRAY['/jetson-images/devkits/igx-orin-devkit.png']::text[], ARRAY['nvidia','jetson','edge-ai','devkits']::text[], false, true, 12, 'carry_in'),
('JTSN-ORIN-NANO-DEVKIT', 'ORIN-NANO-DEVKIT', 'Jetson Series', 'Jetson Orin Nano ชุดพัฒนา', E'ชุดพัฒนา Orin Nano มาตรฐาน 67 TOPS\n\nStandard Orin Nano Dev Kit. 67 TOPS AI performance.\n\nSpecs: Module: Orin Nano 8GB (67 TOPS)', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'orin-nano-devkit', '/jetson-images/devkits/orin-nano-devkit-1.jpg', ARRAY['/jetson-images/devkits/orin-nano-devkit-1.jpg','/jetson-images/devkits/orin-nano-devkit-2.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','devkits']::text[], false, true, 12, 'carry_in'),
('JTSN-AGX-XAVIER-DEVKIT', 'AGX-XAVIER-DEVKIT', 'Jetson Series', 'Jetson AGX Xavier ชุดพัฒนา', E'ชุดพัฒนา AGX Xavier 32 TOPS, GPU 512-core, 32GB LPDDR4x\n\nAGX Xavier Dev Kit. 32 TOPS, 512-core Volta, 32GB LPDDR4x.\n\nSpecs: AI: 32 TOPS', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'agx-xavier-devkit', '/jetson-images/devkits/agx-xavier-devkit-1.jpg', ARRAY['/jetson-images/devkits/agx-xavier-devkit-1.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','devkits']::text[], false, true, 12, 'carry_in'),
('JTSN-XAVIER-NX-DEVKIT', 'XAVIER-NX-DEVKIT', 'Jetson Series', 'Jetson Xavier NX ชุดพัฒนา', E'ชุดพัฒนากะทัดรัด Xavier NX 21 TOPS, 384 CUDA + 48 Tensor\n\nCompact dev kit with Xavier NX. 21 TOPS, 384 CUDA + 48 Tensor.\n\nSpecs: AI: 21 TOPS', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'xavier-nx-devkit', '/jetson-images/devkits/xavier-nx-devkit-1.jpg', ARRAY['/jetson-images/devkits/xavier-nx-devkit-1.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','devkits']::text[], false, true, 12, 'carry_in'),
('JTSN-TX2-DEVKIT', 'TX2-DEVKIT', 'Jetson Series', 'Jetson TX2 ชุดพัฒนา', E'ชุดพัฒนา TX2 256 CUDA cores, 8GB LPDDR4\n\nTX2 Dev Kit. 256 CUDA cores, 8GB LPDDR4.\n\nSpecs: GPU: 256 CUDA Pascal', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'tx2-devkit', '/jetson-images/devkits/tx2-devkit-1.png', ARRAY['/jetson-images/devkits/tx2-devkit-1.png']::text[], ARRAY['nvidia','jetson','edge-ai','devkits']::text[], false, true, 12, 'carry_in'),
('JTSN-NANO-DEVKIT', 'NANO-DEVKIT', 'Jetson Series', 'Jetson Nano ชุดพัฒนา', E'ชุดพัฒนา Jetson ราคาประหยัดสุด 128 CUDA cores, 4GB LPDDR4\n\nMost affordable Jetson dev kit. 128 CUDA cores, 4GB LPDDR4.\n\nSpecs: GPU: 128 CUDA Maxwell', 'ชุดพัฒนา Developer Kit', 0, 'rfq', 'nano-devkit', '/jetson-images/devkits/nano-devkit-1.jpg', ARRAY['/jetson-images/devkits/nano-devkit-1.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','devkits']::text[], false, true, 12, 'carry_in'),
('JTSN-CARRIER-Y-C18', 'CARRIER-Y-C18', 'Jetson Series', 'Carrier Board Y-C18', E'อุตสาหกรรมสำหรับ Orin NX/Nano 100x79x22.8mm (77g) HDMI, USB3.0, GbE, MIPI CSI, M.2\n\nIndustrial-grade for Orin NX/Nano. 100x79x22.8mm (77g). HDMI, 4xUSB3.0, GbE, 2x MIPI CSI, 3x M.2, GPIO/I2C/SPI/I2S/CAN.\n\nSpecs: Module: Orin NX/Nano | Size: 100x79x22.8mm (77g)', 'บอร์ดพื้นฐาน Carrier Board', 0, 'rfq', 'carrier-y-c18', '/jetson-images/carrier-boards/y-c18-1.jpg', ARRAY['/jetson-images/carrier-boards/y-c18-1.jpg','/jetson-images/carrier-boards/y-c18-2.jpg']::text[], ARRAY['nvidia','jetson','edge-ai','carrier-boards']::text[], false, true, 12, 'carry_in'),
